13	// libraryPath resolves the configured library path relative to the per-request
14	// working dir (from ctx via WithWorkingDir, falling back to r.WorkingDir).
15	func (r *mutationResolver) libraryPath(ctx context.Context) (string, error) {
16		wd := r.workingDir(ctx)
17		cfg, err := config.LoadWithWorkingDir(wd)
18		if err != nil {
19			return "", fmt.Errorf("loading config: %w", err)
20		}
21		if cfg.Library == nil || cfg.Library.Path == "" {
22			return "", fmt.Errorf("library not configured")
23		}
24		p := cfg.Library.Path
25		if !filepath.IsAbs(p) {
26			p = filepath.Join(wd, p)
27		}
28		if _, err := os.Stat(p); err != nil {
29			return "", fmt.Errorf("library path not found: %w", err)
30		}
31		return p, nil
32	}
